import json
from express import express
from jsonschema import Draft7Validator

class Solution:
    def __init__(self):
        pass

    def middleware(self, req, res):
        try:
            route_parameters = json.loads(req.body['routeParameters'])
            schema = '{"type": "object", "properties": {"id": {"type": "integer"}, "name": {"type": "string"}}'
            validate = Draft7Validator(schema)
            result = validate.validate(route_parameters)
            if result.errors():
                res.status(400).send({'error': 'Invalid request'})
            else:
                res.send('')
        except Exception as e:
            res.status(400).send({'error': 'Invalid request'})

    def main(self):
        app = express()
        app.use(self.middleware)
        app.listen(3000, lambda: print('Server listening on port 3000'))

if __name__ == '__main__':
    solution = Solution()
    solution.main()
